// Get entry index for species+form (national dex ID)
inline int getEntryIndex(uint16_t natdex, uint8_t form = 0) {
    if (natdex >= 1424) return 0;
    if (form == 0) return natdex;
    uint16_t fsi = FORM_STATS_INDEX[natdex];
    if (fsi == 0) return natdex;
    int idx = fsi + form;
    return (idx < 1424) ? idx : natdex;
}

inline uint16_t getAbility(uint16_t natdex, uint8_t form, int abilityType) {
    int idx = getEntryIndex(natdex, form);
    const auto& e = ABILITIES[idx];
    if (abilityType == 0) return e.ab0;
    if (abilityType == 1) return e.ab1;
    if (abilityType == 2) return e.abH;
    return e.ab0;
}

inline uint8_t getGenderRatio(uint16_t natdex, uint8_t form = 0) {
    return GENDER_RATIO[getEntryIndex(natdex, form)];
}

inline uint8_t getBaseFriendship(uint16_t natdex, uint8_t form = 0) {
    return BASE_FRIENDSHIP[getEntryIndex(natdex, form)];
}

inline uint8_t getGrowthRate(uint16_t natdex, uint8_t form = 0) {
    return GROWTH_RATE[getEntryIndex(natdex, form)];
}

